import sys
import json
import logging
import os
import subprocess
import glob
import shutil
import tempfile

AR_TOOL = "riscv32-elf-ar"

def rearchive_static_lib(original_path, output_path, ar_tool=AR_TOOL):
    original_path = os.path.abspath(original_path)
    output_path = os.path.abspath(output_path)
    with tempfile.TemporaryDirectory() as tmpdir:
        is_thin = False
        try:
            subprocess.run(
                [ar_tool, "x", original_path],
                cwd=tmpdir,
                check=True,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL
            )
        except subprocess.CalledProcessError:
            is_thin = True

        object_files = []

        if is_thin:
            # Thin archive: list member paths, recreate directory layout
            result = subprocess.run(
                [ar_tool, "t", original_path],
                check=True,
                stdout=subprocess.PIPE,
                universal_newlines=True
            )
            obj_rel_paths = result.stdout.strip().splitlines()
            for rel_path in obj_rel_paths:
                src_path = os.path.join(os.path.dirname(original_path), rel_path)
                dst_path = os.path.join(tmpdir, rel_path)
                dst_dir = os.path.dirname(dst_path)

                if not os.path.isfile(src_path):
                    raise FileNotFoundError(f"Missing object for thin archive: {src_path}")

                os.makedirs(dst_dir, exist_ok=True)
                try:
                    shutil.copy(src_path, dst_path)
                except shutil.SameFileError:
                    pass
                object_files.append(rel_path)
                # Rebuild thick archive with embedded .o files
                subprocess.run(
                    [ar_tool, "rcs", output_path] + object_files,
                    cwd=tmpdir,
                    check=True
                )
        else:
            # Thick archive: just copy
            shutil.copy2(original_path, output_path)

def main(sdk_dir: str, sdk_config: str, output_path: str):
    cmd = ['make', sdk_config]
    sdk = sdk_dir + '/wise-sdk'
    with subprocess.Popen(cmd, cwd=sdk, stdout=subprocess.PIPE) as s:
        outs, errs = s.communicate()
        code = s.wait()
        if code != 0:
            raise Exception('Command %r failed: %d' % (cmd, code))
    cmd = ['make']
    with subprocess.Popen(cmd, cwd=sdk, stdout=subprocess.PIPE) as s:
        code = s.wait()
        if code != 0:
            raise Exception('Command %r failed: %d' % (cmd, code))

    os.makedirs(output_path, exist_ok=True)

    for lib_path in glob.glob(os.path.join(sdk, "**", "*.a"), recursive=True):
        rel_path = os.path.relpath(lib_path, sdk)
        dest_path = os.path.join(output_path, rel_path)
        os.makedirs(os.path.dirname(dest_path), exist_ok=True)
        rearchive_static_lib(lib_path, dest_path)

    built_ts = os.path.join(sdk, "include/generated/timestamp_autogenerated.h")
    shutil.copy2(built_ts, output_path + "timestamp_autogenerated.h")

if __name__ == '__main__':
    main(sdk_dir=sys.argv[1], sdk_config=sys.argv[2], output_path=sys.argv[4])
